import scala.collection.mutable.PriorityQueue

def solve(n: Long, edges: Array[Array[Long]]): Long = {
    val adj = Array.fill(n.toInt)(List.empty[(Int, Long)])
    val reverseAdj = Array.fill(n.toInt)(List.empty[(Int, Long)])

    for (e <- edges) {
        val u = e(0).toInt
        val v = e(1).toInt
        val w = e(2)
        adj(u) = (v, w) :: adj(u)
        reverseAdj(v) = (u, w) :: reverseAdj(v)
    }

    val dist = Array.fill(n.toInt, 2)(Long.MaxValue)
    dist(0)(0) = 0L

    val pq = PriorityQueue.empty[(Long, Int, Boolean)](
        Ordering.by[(Long, Int, Boolean), Long](_._1).reverse
    )
    pq.enqueue((0L, 0, false))

    while (pq.nonEmpty) {
        val (currentDist, u, used) = pq.dequeue()

        if (currentDist > dist(u)(if (used) 1 else 0)) {
            // Skip if we already have a better distance
            ()
        } else {
            // Explore normal edges
            for ((v, w) <- adj(u)) {
                val newDist = currentDist + w
                if (newDist < dist(v)(if (used) 1 else 0)) {
                    dist(v)(if (used) 1 else 0) = newDist
                    pq.enqueue((newDist, v, used))
                }
            }

            // If switch not used, try using it
            if (!used) {
                for ((v, w) <- reverseAdj(u)) {
                    val newDist = currentDist + 2 * w
                    if (newDist < dist(v)(1)) {
                        dist(v)(1) = newDist
                        pq.enqueue((newDist, v, true))
                    }
                }
            }
        }
    }

    val result = math.min(dist((n - 1).toInt)(0), dist((n - 1).toInt)(1))
    if (result == Long.MaxValue) -1 else result
}
