#include <unordered_map>
#include <utility>

using namespace std;

long long solve(long long n, std::vector<std::vector<long long>> edges) {
    // Build adjacency list
    vector<vector<pair<long long, long long>>> adj(n);
    // Also build reverse adjacency list for incoming edges
    vector<vector<pair<long long, long long>>> reverse_adj(n);
    for (const auto& e : edges) {
        long long u = e[0], v = e[1], w = e[2];
        adj[u].emplace_back(v, w);
        reverse_adj[v].emplace_back(u, w);
    }

    // Dijkstra's algorithm with state (node, whether we've used a switch)
    // dist[node][used] = min cost to reach node with used (0 or 1)
    vector<vector<long long>> dist(n, vector<long long>(2, LLONG_MAX));
    dist[0][0] = 0;

    // Priority queue: (distance, node, used_switch)
    priority_queue<tuple<long long, long long, bool>, 
                   vector<tuple<long long, long long, bool>>, 
                   greater<tuple<long long, long long, bool>>> pq;
    pq.emplace(0, 0, false);

    while (!pq.empty()) {
        auto [current_dist, u, used] = pq.top();
        pq.pop();

        if (current_dist > dist[u][used]) continue;

        // Explore normal edges
        for (const auto& [v, w] : adj[u]) {
            if (current_dist + w < dist[v][used]) {
                dist[v][used] = current_dist + w;
                pq.emplace(dist[v][used], v, used);
            }
        }

        // If we haven't used the switch yet, try using it at u
        if (!used) {
            for (const auto& [v, w] : reverse_adj[u]) {
                // The edge is v->u, we reverse it to u->v with cost 2*w
                if (current_dist + 2 * w < dist[v][true]) {
                    dist[v][true] = current_dist + 2 * w;
                    pq.emplace(dist[v][true], v, true);
                }
            }
        }
    }

    long long result = min(dist[n-1][0], dist[n-1][1]);
    return result == LLONG_MAX ? -1 : result;
}
